solution_code:
#include <array>
#include <cstddef>
#include <iostream>

int main()
{
    std::array<int, 6> arr{};

    for (std::size_t i{ 0 }; i < arr.size(); ++i)
        std::cin >> arr[i];

    int index{};
    std::cin >> index;

    std::cout << "Size: " << arr.size() << '\n';

    if (index >= 0 && static_cast<std::size_t>(index) < arr.size())
        std::cout << "Value: " << arr[static_cast<std::size_t>(index)] << '\n';
    else
        std::cout << "Error: index out of range" << '\n';

    return 0;
}
